// ─────────────────────────────────────────────
// Simulate the output of a node you want to
// snapshot-test (e.g. a transform/code node)
// ─────────────────────────────────────────────
function transformOrder(raw) {
  return {
    orderId:    raw.id,
    customer:   raw.customer.toUpperCase(),
    totalPrice: (raw.items.reduce((s, i) => s + i.price * i.qty, 0)).toFixed(2),
    itemCount:  raw.items.length,
    status:     raw.status === 'new' ? 'PENDING' : 'PROCESSED'
  };
}

const rawOrder = {
  id: 'ORD-001',
  customer: 'sanket',
  status: 'new',
  items: [
    { name: 'Widget A', price: 10, qty: 2 },
    { name: 'Widget B', price: 5,  qty: 3 }
  ]
};

const output = transformOrder(rawOrder);
return [{ json: { currentOutput: output } }];

// ─────────────────────────────────────────────
// SNAPSHOT: This is your saved known-good output
// First run: copy currentOutput here as snapshot
// Future runs: compare against it automatically
// ─────────────────────────────────────────────
const SNAPSHOT = {
  orderId:    'ORD-001',
  customer:   'SANKET',
  totalPrice: '35.00',
  itemCount:  2,
  status:     'PENDING'
};

const current = $json.currentOutput;

// Deep compare helper
function deepEqual(a, b) {
  if (typeof a !== typeof b) return false;
  if (typeof a !== 'object') return a === b;
  const ka = Object.keys(a), kb = Object.keys(b);
  if (ka.length !== kb.length) return false;
  return ka.every(k => deepEqual(a[k], b[k]));
}

// Find field-level diffs
const diffs = [];
for (const key of Object.keys(SNAPSHOT)) {
  if (!deepEqual(SNAPSHOT[key], current[key])) {
    diffs.push({
      field:    key,
      snapshot: SNAPSHOT[key],
      current:  current[key]
    });
  }
}

const passed = diffs.length === 0;

return [{
  json: {
    snapshotTest: passed ? '✅ SNAPSHOT MATCH' : '❌ SNAPSHOT MISMATCH',
    passed,
    diffs,
    tip: passed
      ? 'Output matches saved snapshot.'
      : 'Update SNAPSHOT const above if change is intentional.'
  }
}];

const d = $json;
return [{
  json: {
    result: '❌ Output changed!',
    diffs: d.diffs,
    action: 'Review diffs. If intentional, update SNAPSHOT in Compare Snapshot node.'
  }
}];
